from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import TypeVar, Generic

T = TypeVar('T')

@dataclass
class Command(ABC):
    """Base class for all commands."""
    pass

class CommandHandler(ABC, Generic[T]):
    """Base class for command handlers. Returns None or ID."""
    @abstractmethod
    async def handle(self, command: T) -> None:
        pass

@dataclass
class PlaceOrderCommand(Command):
    order_id: UUID
    customer_id: UUID
    items: List[dict]
    shipping_address: dict

class PlaceOrderHandler(CommandHandler[PlaceOrderCommand]):
    def __init__(self, order_repository: OrderRepository, event_bus: EventBus):
        self._order_repository = order_repository
        self._event_bus = event_bus

    async def handle(self, command: PlaceOrderCommand) -> None:
        order = Order.create(id=command.order_id, customer_id=command.customer_id)
        for item in command.items:
            order.add_item(item["product_id"], item["quantity"], item["price"])
        order.place(shipping_address=Address(**command.shipping_address))
        await self._order_repository.save(order)
        for event in order.collect_events():
            await self._event_bus.publish(event)

from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import TypeVar, Generic

T = TypeVar('T')
R = TypeVar('R')

@dataclass
class Query(ABC):
    pass

class QueryHandler(ABC, Generic[T, R]):
    @abstractmethod
    async def handle(self, query: T) -> R:
        pass

@dataclass
class GetOrderQuery(Query):
    order_id: UUID

@dataclass
class OrderDto:
    id: UUID
    customer_id: UUID
    status: str
    items: list
    total: float
    shipping_address: dict
    placed_at: Optional[str]

class GetOrderHandler(QueryHandler[GetOrderQuery, OrderDto]):
    def __init__(self, read_store: ReadStore):
        self._read_store = read_store

    async def handle(self, query: GetOrderQuery) -> OrderDto:
        data = await self._read_store.get(f"order:{query.order_id}")
        if not data:
            raise OrderNotFoundError(query.order_id)
        return OrderDto(**data)

class Mediator:
    def __init__(self):
        self._command_handlers: Dict[Type, CommandHandler] = {}
        self._query_handlers: Dict[Type, QueryHandler] = {}

    def register_command_handler(self, command_type: Type, handler: CommandHandler) -> None:
        self._command_handlers[command_type] = handler

    def register_query_handler(self, query_type: Type, handler: QueryHandler) -> None:
        self._query_handlers[query_type] = handler

    async def send(self, command: Command) -> None:
        handler = self._command_handlers.get(type(command))
        if not handler:
            raise HandlerNotFoundError(f"No handler for {type(command)}")
        await handler.handle(command)

    async def query(self, query: Query):
        handler = self._query_handlers.get(type(query))
        if not handler:
            raise HandlerNotFoundError(f"No handler for {type(query)}")
        return await handler.handle(query)

class GetOrderHandler:
    async def handle(self, query: GetOrderQuery) -> OrderDto:
        data = await self._read_store.get(f"order:{query.order_id}")
        if not data:
            raise OrderNotFoundError(query.order_id)
        return OrderDto(**data)  # Pure read, no writes
